// ── Segment & theme type helpers ─────────────────────────────────────

/** Available business segments: pessoa física, pessoa jurídica, ultravioleta. */
export type SegmentKey = "pf" | "pj" | "uv";

/** Available color-scheme modes. */
export type ThemeKey = "light" | "dark";

